package com.example.nofiltercoffee; import android.content.*; import android.os.*; import android.view.*; import android.widget.*; import androidx.appcompat.app.*;
public class LoginActivity extends AppCompatActivity{EditText e,p;TextView err;protected void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_login);e=findViewById(R.id.edtEmail);p=findViewById(R.id.edtPassword);err=findViewById(R.id.txtError);findViewById(R.id.btnLogin).setOnClickListener(v->{if(UserSession.login(this,e.getText().toString().trim(),p.getText().toString())){startActivity(new Intent(this,HomeActivity.class).setFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP|Intent.FLAG_ACTIVITY_NEW_TASK));finish();}else{err.setText("Invalid email or password.");err.setVisibility(View.VISIBLE);}});findViewById(R.id.btnGoSignup).setOnClickListener(v->{startActivity(new Intent(this,SignupActivity.class));finish();});}}
